import java.io.IOException;

public class CommandInjectionDemo {

    public static void main(String[] args) {
        String userInput = "example.txt";

        // Validate and sanitize user input before using it
        if (!userInput.matches("[a-zA-Z0-9_]+\\.txt")) {
            System.err.println("Invalid file name provided.");
            return;
        }

        try {
            // Use ProcessBuilder to execute the command safely
            ProcessBuilder processBuilder = new ProcessBuilder("cat", userInput);
            Process process = processBuilder.start();

            // Reading the output of the command
            int result;
            while ((result = process.getInputStream().read()) != -1) {
                System.out.print((char) result);
            }

        } catch (IOException e) {
            System.err.println("An error occurred during command execution: " + e.getMessage());
        }
    }
}

